VALUES
  ('optometrist-moex-03144', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關低視力患者選用輔具的原則，以下何者錯誤？', '["以光學輔具為首要優先之考量", "矯正視力如在0.1至0.3左右者，輔以一些檯燈、大時鐘、大字鍵電話等非光學輔具即可完成日常生活 作業", "使用光學輔具的先決條件是，患者需具備基本視覺能力，能夠定位或是能注意到特定目標的方位", "輔具的放大倍率愈高，可視的範圍就愈小"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "9fd7bcaf8486", "answer_pdf_sha1": "1d4fab479553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03145', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '低視能患者產生的失能眩光，主要是由於散射光線在眼內使視網膜成像產生重疊，成像的對比度下降， 因而降低了視覺效能及清晰度，可建議此類患者使用何種光學輔具？', '["偏光鏡及濾鏡片", "放大鏡", "望遠鏡", "擴視機"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "9fd7bcaf8486", "answer_pdf_sha1": "1d4fab479553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03146', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關擴視機的功能選擇，以下何者錯誤？', '["視力較差的病患適合選用放大鏡，而視力不錯的病患則可考量選用擴視機", "畏光型疾病患者須注意擴視機「亮度調整」的功能", "視網膜疾病與對比敏感不佳的患者須注意擴視機「燈光補強」及「對比色調整」的功能", "眼球震顫的患者須注意擴視機「閱讀定位線」與「遮蔽視窗」的功能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "9fd7bcaf8486", "answer_pdf_sha1": "1d4fab479553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03147', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '一位青光眼病患，兩眼中心視力均達 0.9，但雙眼中心視野僅有 15 度左右，若想學開車，您給他的建議 為何？', '["使用高倍眼鏡型望遠鏡", "使用偏光眼鏡", "使用立體眼鏡", "不建議開車"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "9fd7bcaf8486", "answer_pdf_sha1": "1d4fab479553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03148', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有一位雙眼視力0.15的病患想使用電腦，但覺得電腦螢幕太亮很刺眼，其正確建議為何？①使用擴視機', '["調降電腦螢幕的亮度", "戴上適合的濾鏡眼鏡", "使用望遠鏡", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "9fd7bcaf8486", "answer_pdf_sha1": "1d4fab479553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03149', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關視野缺損的低視力患者，其閱讀時的調整方式，下列何者正確？', '["周邊視野缺損者，應將閱讀資料放大", "中心視野缺損者，應將閱讀資料縮小", "閱讀時，應使用望遠鏡輔助", "中心視野缺損者，應訓練偏心閱讀（eccentric viewing）的能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "9fd7bcaf8486", "answer_pdf_sha1": "1d4fab479553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03150', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關各類視覺缺損形態之處置，以下何者錯誤？', '["畏光型及明暗適應困難型可利用透光度低的濾鏡片，以減少室內與室外光線的落差對比", "眼球震顫型可藉由屈光矯正或濾鏡片提升其視力值或調整光線進入眼球的入光量，以降低眼球震顫之 頻率與幅度", "配戴隱形眼鏡會強化眼球震顫之頻率與幅度", "視野限縮型可藉由稜鏡補足視野缺損，協助雙眼融像"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "9fd7bcaf8486", "answer_pdf_sha1": "1d4fab479553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03151', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關視皮質損傷患者之典型視覺行為特徵，以下何者錯誤？', '["多數患者對特定顏色有所偏好，尤其是紅、綠兩種顏色", "移動物品能引起視覺注意", "觸摸額頭或有視覺威脅下，會延遲甚至沒有眨眼保護反應", "凝視光源或無目的的凝視"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "9fd7bcaf8486", "answer_pdf_sha1": "1d4fab479553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03152', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '因腫瘤壓迫導致視野的右側偏盲，右半身的視野是看不見的，建議採用稜鏡的原理來計算所需求的視野 範圍，以下處置何者正確？', '["右眼稜鏡基底朝內，左眼稜鏡基底朝內", "右眼稜鏡基底朝內，左眼稜鏡基底朝外", "右眼稜鏡基底朝外，左眼稜鏡基底朝內", "右眼稜鏡基底朝外，左眼稜鏡基底朝外"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "9fd7bcaf8486", "answer_pdf_sha1": "1d4fab479553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03153', 'optometrist', 'optometrist-moex-106-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '以下何項表徵的出現有助於流行性角結膜炎（epidemic keratoconjunctivitis）的診斷？', '["視網膜出血", "眼壓升高", "視神經盤水腫（optic disc edema）", "形成僞膜（pseudomembranes）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "9fd7bcaf8486", "answer_pdf_sha1": "1d4fab479553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
